import{_ as e,o as i,c as l,a2 as t}from"./chunks/framework.BflysNKA.js";const u=JSON.parse('{"title":"渠道与节点切换","description":"","frontmatter":{},"headers":[],"relativePath":"guide/channels-and-failover.md","filePath":"guide/channels-and-failover.md","lastUpdated":1778577020000}'),r={name:"guide/channels-and-failover.md"};function n(s,a,o,d,p,h){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="渠道与节点切换" tabindex="-1">渠道与节点切换 <a class="header-anchor" href="#渠道与节点切换" aria-label="Permalink to &quot;渠道与节点切换&quot;">​</a></h1><p>小蓝中转站 在网关侧处理渠道切换和故障转移。客户端侧最稳的做法，是把已经配置好的地址保持不变。</p><p>在日常使用中，不同上游模型厂商偶尔会出现区域性波动、单条渠道失效、某个时段超时增多。<br> 这种时候，真正需要变动的通常不是你本地写好的 Endpoint，而是网关内部到底该选哪条可用渠道。</p><p>常见工具对应的地址保持如下：</p><table tabindex="0"><thead><tr><th>工具类型</th><th>保持使用的地址</th></tr></thead><tbody><tr><td>OpenAI 兼容工具</td><td><code>https://xiaolan1.cn/v1</code></td></tr><tr><td>Claude Code</td><td><code>https://xiaolan1.cn</code></td></tr><tr><td>Gemini CLI 当前版本</td><td><code>https://xiaolan1.cn</code></td></tr></tbody></table><p>很多用户遇到响应变慢、单次超时，第一反应是去客户端里换地址、改 endpoint，甚至把别的教程里的 URL 贴进来。对于已经接到 小蓝中转站 的工具来说，这通常不是优先处理方式。</p><h2 id="智能路由与高可用" tabindex="-1">智能路由与高可用 <a class="header-anchor" href="#智能路由与高可用" aria-label="Permalink to &quot;智能路由与高可用&quot;">​</a></h2><p>一次请求进入网关后，大致会经历这几层判断：</p><ol><li><strong>先按分组和模型筛选</strong>：当前 Key 所在分组、模型权限、渠道可用状态，先决定“哪些渠道有资格被选中”。</li><li><strong>再按优先级选渠道</strong>：同一分组下，同一模型可能挂了多条渠道。网关会优先尝试当前优先级更高的可用渠道。</li><li><strong>遇到可重试错误再换下一条</strong>：如果这次请求返回的是可重试错误，网关才会继续尝试下一条可用渠道。</li><li><strong><code>auto</code> 分组时可继续跨分组</strong>：如果你的 Key 走的是 <code>auto</code> 分组，并且当前配置允许跨分组重试，当前分组的可用优先级用完后，才会继续尝试下一个分组。</li></ol><p>这意味着：同一把 Key、同一个已配置地址，网关会尽量处理“同模型、同权限范围内”的底层通道波动。<br> 客户端侧更值得优先检查的，通常是模型、Key、上下文大小和超时设置。</p><h2 id="开发者需要做什么" tabindex="-1">开发者需要做什么？ <a class="header-anchor" href="#开发者需要做什么" aria-label="Permalink to &quot;开发者需要做什么？&quot;">​</a></h2><p>OpenAI 兼容脚本或客户端，通常保持下面这类地址配置即可：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> BASE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;https://xiaolan1.cn/v1&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你使用的是 Claude Code 或 Gemini CLI，就继续保留它们各自文档里的根地址配置，不要因为某次变慢就临时改成别的路径。</p><p>真正需要你手动处理的，通常只有三类：</p><ul><li>换模型：当前模型维护、拥堵，或这个模型本身就只有少量上游时，切同类模型通常更快。</li><li>换 Key：某把 Key 被禁用、泄露或额度耗尽。</li><li>缩上下文：请求太大导致慢或失败。</li></ul><h2 id="故障转移能解决什么-不能解决什么" tabindex="-1">故障转移能解决什么，不能解决什么 <a class="header-anchor" href="#故障转移能解决什么-不能解决什么" aria-label="Permalink to &quot;故障转移能解决什么，不能解决什么&quot;">​</a></h2><p>故障转移主要解决的是“底层某条渠道暂时不稳”这类问题，但不是所有错误都能靠切通道修好。</p><h3 id="更可能由故障转移缓解的问题" tabindex="-1">更可能由故障转移缓解的问题 <a class="header-anchor" href="#更可能由故障转移缓解的问题" aria-label="Permalink to &quot;更可能由故障转移缓解的问题&quot;">​</a></h3><ul><li>单条渠道临时不可用</li><li>503 / 504 这类上游不可用或超时</li><li>单次偶发超时</li><li>同一模型在某个时段明显变慢，但换同模型的其他渠道后可恢复</li></ul><h3 id="通常不是节点问题" tabindex="-1">通常不是节点问题 <a class="header-anchor" href="#通常不是节点问题" aria-label="Permalink to &quot;通常不是节点问题&quot;">​</a></h3><ul><li>401：Key 错误、余额不足或 Key 被禁用</li><li>400：请求格式或模型名错误</li><li>404：模型名不存在</li><li>429：频率或额度限制</li><li>账户或分组本身没有这个模型权限</li></ul><p>这些错误继续改 endpoint，通常不会变好。</p><h2 id="遇到大规模不可用" tabindex="-1">遇到大规模不可用 <a class="header-anchor" href="#遇到大规模不可用" aria-label="Permalink to &quot;遇到大规模不可用&quot;">​</a></h2><p>如果在模型广场或状态接口看到大面积报错，可以先：</p><ol><li>在客户端内暂时切至其他厂商的同级别模型（如从 Claude 切换到 Gemini）。</li><li>前往 <a href="https://xiaolan1.cn/api/status" target="_blank" rel="noreferrer">状态探针页面</a> 查看整体服务是否正常。</li></ol><p>如果只是单个模型不稳，不必第一时间重做整套配置。先换同类轻量模型验证，通常更快。</p><p>状态探针更适合看“站点是不是整体可用”，不适合拿来证明“某个具体模型这一刻一定正常”。<br> 单个模型的拥堵、维护或上游限流，还是要回到模型本身来判断。</p><h2 id="客户端超时怎么设" tabindex="-1">客户端超时怎么设 <a class="header-anchor" href="#客户端超时怎么设" aria-label="Permalink to &quot;客户端超时怎么设&quot;">​</a></h2><p>如果你的工具允许设置超时时间，不要设得太短。复杂模型和长上下文任务可能需要更久。</p><p>建议：</p><ul><li>普通聊天：60 秒以上</li><li>代码库分析：120 秒以上</li><li>图像、音频、视频：按任务类型放宽</li></ul><p>超时设得过短时，网关还没来得及完成同模型的重试，客户端就已经先断开了。<br> 表面看像“整条链路全挂了”，实际可能只是你给的等待时间太短。</p><h2 id="一个更省时间的判断顺序" tabindex="-1">一个更省时间的判断顺序 <a class="header-anchor" href="#一个更省时间的判断顺序" aria-label="Permalink to &quot;一个更省时间的判断顺序&quot;">​</a></h2><p>遇到问题时，优先按这个顺序判断：</p><ol><li>先看是不是 401 / 404 / 429 这类明确错误</li><li>再看状态探针和模型广场是否有整体异常</li><li>再换同类轻量模型做最小验证</li><li>最后才考虑是不是当前模型所在渠道不稳</li></ol><p>这样能避免把“Key 没权限”或“模型名写错”误判成节点问题。</p>',37)])])}const b=e(r,[["render",n]]);export{u as __pageData,b as default};
